#include<bits/stdc++.h>
using namespace std;
typedef long long LL;

LL a[25], b[25];

int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
	for(int i = 1; i <= n; i++)
		cin >> b[i];
	sort(a, a + n + 1);
	sort(b, b + n + 1);
	LL mul = 1;
	for(int i = 1; i <= n; i++)
	{
		int cnt = upper_bound(a + 1, a + n + 1, b[i]) - a - 1;
		mul *= cnt - i + 1;
	}
	cout << mul;
}
